const hour = new Date().getUTCHours();
const start = parseInt($env.SYNC_WORKING_HOURS_START || '7', 10);
const end   = parseInt($env.SYNC_WORKING_HOURS_END   || '21', 10);
const isManual = !!($input.first().json.body || $input.first().json.manual);
if (!isManual && (hour < start || hour >= end)) return [];
return [{ json: { triggered_at: new Date().toISOString(), manual: isManual } }];

const projectsRaw = $('Fetch Clockify Projects').first().json;
const usersRaw = $('Fetch Clockify Users').first().json;

const projectsOk = Array.isArray(projectsRaw);
const usersOk = Array.isArray(usersRaw);

if (!projectsOk || !usersOk) {
  // Post warning to TL channel
  const msg = !projectsOk && !usersOk
    ? '[Pipemind] Clockify sync échoué — les deux endpoints Clockify sont indisponibles. La dernière image connue est conservée.'
    : !projectsOk
      ? '[Pipemind] Clockify sync échoué — endpoint projects indisponible.'
      : '[Pipemind] Clockify sync échoué — endpoint users indisponible.';
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `https://discord.com/api/v10/channels/${$env.TL_CHANNEL_ID}/messages`,
      headers: { 'Authorization': `Bot ${$env.DISCORD_BOT_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: msg }),
    });
  } catch(e) { /* non-critical */ }
  return [];
}

// Build users map: clockify_user_id -> { name, email }
const usersMap = {};
for (const u of usersRaw) {
  usersMap[u.id] = { name: u.name, email: u.email };
}

// Normalize projects
const projects = projectsRaw.map(p => ({
  clockify_project_id: p.id,
  name: String(p.name || '').slice(0, 200),
  client_name: p.clientName ? String(p.clientName).slice(0, 200) : null,
  memberships: (p.memberships || [])
    .filter(m => m.membershipStatus === 'ACTIVE')
    .map(m => ({ clockify_user_id: m.userId })),
}));

return [{ json: { projects, users_map: usersMap } }];

const { projects, users_map } = $('Validate API Responses').first().json;
const rosterRows = $('Fetch Roster').all().map(i => i.json);

// Build clockify_user_id -> discord_id map
const userToDiscord = {};
for (const r of rosterRows) {
  if (r.clockify_user_id) userToDiscord[r.clockify_user_id] = r.discord_id;
}

const triggeredAt = $('Check Working Hours').first().json.triggered_at;
const unmappedUserIds = new Set();

// Build project upsert rows
const projectRows = projects.map(p => ({
  id: p.clockify_project_id,
  name: p.name,
  client_name: p.client_name,
}));

// Build membership rows
const membershipRows = [];
for (const p of projects) {
  for (const m of p.memberships) {
    const discordId = userToDiscord[m.clockify_user_id] || null;
    if (!discordId) unmappedUserIds.add(m.clockify_user_id);
    membershipRows.push({
      clockify_project_id: p.clockify_project_id,
      clockify_user_id: m.clockify_user_id,
      roster_discord_id: discordId,
      is_unmapped: !discordId,
    });
  }
}

// Build project upsert SQL with parameterized values
let projectSql = 'SELECT 1;'; // no-op placeholder
const projectParams = [];
if (projectRows.length > 0) {
  const placeholders = projectRows.map((_, i) => {
    const base = i * 3;
    return `($${base+1}, $${base+2}, $${base+3}, true, now())`;
  }).join(', ');
  projectSql = `INSERT INTO pipemind.clockify_projects (clockify_project_id, name, client_name, is_active, last_synced_at)\nVALUES ${placeholders}\nON CONFLICT (clockify_project_id) DO UPDATE SET\n  name = EXCLUDED.name,\n  client_name = EXCLUDED.client_name,\n  is_active = true,\n  last_synced_at = EXCLUDED.last_synced_at,\n  updated_at = now();`;
  for (const r of projectRows) {
    projectParams.push(r.id, r.name, r.client_name);
  }
}

// Build membership upsert SQL
let membershipSql = 'SELECT 1;'; // no-op placeholder
const membershipParams = [];
if (membershipRows.length > 0) {
  const placeholders = membershipRows.map((_, i) => {
    const base = i * 4;
    return `($${base+1}, $${base+2}, $${base+3}, $${base+4}, true, now())`;
  }).join(', ');
  membershipSql = `INSERT INTO pipemind.project_memberships (clockify_project_id, clockify_user_id, roster_discord_id, is_unmapped, is_active, last_synced_at)\nVALUES ${placeholders}\nON CONFLICT (clockify_project_id, clockify_user_id) DO UPDATE SET\n  roster_discord_id = EXCLUDED.roster_discord_id,\n  is_unmapped = EXCLUDED.is_unmapped,\n  is_active = true,\n  last_synced_at = EXCLUDED.last_synced_at,\n  updated_at = now();`;
  for (const r of membershipRows) {
    membershipParams.push(r.clockify_project_id, r.clockify_user_id, r.roster_discord_id, r.is_unmapped);
  }
}

return [{ json: {
  project_sql: projectSql,
  project_params: projectParams,
  membership_sql: membershipSql,
  membership_params: membershipParams,
  triggered_at: triggeredAt,
  unmapped_user_ids: [...unmappedUserIds],
  project_count: projectRows.length,
} }];

const unmapped = $('Build Upsert Data').first().json.unmapped_user_ids || [];
if (unmapped.length > 0) {
  const list = unmapped.join(', ');
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: `https://discord.com/api/v10/channels/${$env.TL_CHANNEL_ID}/messages`,
      headers: { 'Authorization': `Bot ${$env.DISCORD_BOT_TOKEN}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: `[Pipemind] Sync Clockify : les identifiants suivants n'ont pas de correspondance dans le roster et ne peuvent pas être contactés : ${list}. Veuillez mettre à jour le roster.` }),
    });
  } catch(e) { /* non-critical */ }
}
return $input.all();
